export function IcoTrafficFlow() {
  const { palette } = useIlloStyle();
  return (
    <svg viewBox="0 0 200 130" preserveAspectRatio="xMidYMid slice" style={{ width: '100%', height: '100%' }}>
      <rect width="200" height="130" fill={palette.dark} />
      {/* Road background */}
      <rect x="20" y="30" width="160" height="70" rx="6" fill={palette.mid} opacity="0.20" />
      {/* Lane separator */}
      <line x1="20" y1="65" x2="180" y2="65" stroke="rgba(255,255,255,0.12)" strokeWidth="1.5" strokeDasharray="10 6" />
      {/* Flow bands */}
      <rect x="20" y="30" width="160" height="23" rx="5" fill="#4caf50" opacity="0.70" />
      <rect x="20" y="53" width="160" height="24" rx="0" fill={palette.accent} opacity="0.70" />
      <rect x="20" y="77" width="160" height="23" rx="5" fill="#e53935" opacity="0.70" />
      {/* Road border */}
      <rect x="20" y="30" width="160" height="70" rx="6" fill="none" stroke={palette.mid} strokeWidth="2" />
    </svg>
  );
}
